 // Query the version of gdrdrv driver
 int gdr_driver_get_version(gdr_t g, int *major, int *minor);

+typedef enum gdr_attr {
+    GDR_ATTR_USE_PERSISTENT_MAPPING = 1,    // gdrdrv uses persistent mapping
+
+    // For internal use only
+    GDR_ATTR_MAX
+} gdr_attr_t;
+
+// Query the attribute of GDRCopy.
+//
+// This is for querying a system-wide attribute.
+// To query an attribute associated with each memory handle, use gdr_get_info instead.
+int gdr_get_attribute(gdr_t g, gdr_attr_t attr, int *v);
+
 #ifdef __cplusplus
 }
 #endif
diff --git a/src/gdrapi.c b/src/gdrapi.c
index 5e4ea9c..db45869 100644
--- a/src/gdrapi.c
+++ b/src/gdrapi.c
@@ -818,6 +818,39 @@ int gdr_driver_get_version(gdr_t g, int *major, int *minor)
     return 0;
 }

+int gdr_get_attribute(gdr_t g, gdr_attr_t attr, int *v)
+{
+    int ret = 0;
+    int retcode;
+    struct GDRDRV_IOC_GET_ATTR_PARAMS params;
+
+    if (attr < 1 || attr >= GDR_ATTR_MAX) {
+        ret = EINVAL;
+        goto out;
+    }
+
+    // gdrdrv does not support attribute querying.
+    // Always assume that the value is 0.
+    if (g->gdrdrv_version < GDRDRV_MINIMUM_VERSION_WITH_GET_ATTR) {
+        *v = 0;
+        goto out;
+    }
+
+    params.attr = attr;
+    retcode = ioctl(g->fd, GDRDRV_IOC_GET_ATTR, &params);
+    if (-EINVAL == retcode) {
+        // gdrdrv might be too old to query this attr.
+        // Assume 0.
+        *v = 0;
+        goto out;
+    }
+
+    *v = params.val;
+
+out:
+    return ret;
+}
+
 // ==============================================================================
 // Obsoleted API. Provided for compatibility only.
 // ==============================================================================
