+{
+    struct GDRDRV_IOC_GET_ATTR_PARAMS params = {0};
+    int ret = 0;
+
+    if (copy_from_user(&params, _params, sizeof(params))) {
+        gdr_err("copy_from_user failed on user pointer 0x%px\n", _params);
