Author: Pak Markthub <pmarkthub@nvidia.com>
Date:   Fri Sep 9 03:11:31 2022 -0700

    Introduced gdrdrv_remap_pfn_range to avoid the GPL-incompatibility issue on x86 in linux kernel 5.18-rc1 and later
---
 src/gdrdrv/gdrdrv.c | 23 +++++++++++++++++++++--
 1 file changed, 21 insertions(+), 2 deletions(-)

diff --git a/src/gdrdrv/gdrdrv.c b/src/gdrdrv/gdrdrv.c
index 2c50392..0456c31 100644
--- a/src/gdrdrv/gdrdrv.c
+++ b/src/gdrdrv/gdrdrv.c
@@ -1010,6 +1010,25 @@ static const struct vm_operations_struct gdrdrv_vm_ops = {

 /*----------------------------------------------------------------------------*/

+/**
+ * Starting from kernel version 5.18-rc1, io_remap_pfn_range may use a GPL
+ * function. This happens on x86 platforms that have
+ * CONFIG_ARCH_HAS_CC_PLATFORM defined. The root cause is from
+ * pgprot_decrypted implementation that has been changed to use cc_mkdec. To
+ * avoid the GPL-incompatibility issue with our module, which is MIT, we
+ * emulate how io_remap_pfn_range originally works here.
+ */
+static inline int gdrdrv_remap_pfn_range(struct vm_area_struct *vma, unsigned long vaddr, unsigned long pfn, size_t size, pgprot_t prot)
+{
+#if (defined(CONFIG_X86_64) || defined(CONFIG_X86_32)) && defined(CONFIG_ARCH_HAS_CC_PLATFORM)
+    return remap_pfn_range(vma, vaddr, pfn, size, __pgprot(__sme_clr(pgprot_val(prot))));
+#else
+    return io_remap_pfn_range(vma, vaddr, pfn, size, prot);
+#endif
+}
+
+/*----------------------------------------------------------------------------*/
+
 static int gdrdrv_remap_gpu_mem(struct vm_area_struct *vma, unsigned long vaddr, unsigned long paddr, size_t size, int is_wcomb)
 {
     int ret = 0;
@@ -1044,8 +1063,8 @@ static int gdrdrv_remap_gpu_mem(struct vm_area_struct *vma, unsigned long vaddr,
     } else {
         // by default, vm_page_prot should be set to create cached mappings
     }
-    if (io_remap_pfn_range(vma, vaddr, pfn, size, vma->vm_page_prot)) {
-        gdr_err("error in remap_pfn_range()\n");
+    if (gdrdrv_remap_pfn_range(vma, vaddr, pfn, size, vma->vm_page_prot)) {
+        gdr_err("error in gdrdrv_remap_pfn_range()\n");
         ret = -EAGAIN;
         goto out;
     }

commit 1ffe414e3784803dac2c919ee38761e03d0dcc27
Author: Pak Markthub <pmarkthub@nvidia.com>
Date:   Mon Mar 6 01:15:40 2023 -0800

    Implemented basic_small_buffers_mapping test
---
 tests/sanity.cpp | 69 ++++++++++++++++++++++++++++++++++++++++++++++++++++++++
 1 file changed, 69 insertions(+)

diff --git a/tests/sanity.cpp b/tests/sanity.cpp
index 561668f..33d5492 100644
--- a/tests/sanity.cpp
+++ b/tests/sanity.cpp
@@ -393,6 +393,74 @@ BEGIN_GDRCOPY_TEST(basic_unaligned_mapping)
 }
 END_GDRCOPY_TEST

+/**
+ * This unit test is for catching issue-244
+ * (https://github.com/NVIDIA/gdrcopy/issues/244).  The bug occurs when the
+ * first buffer is smaller than the GPU page size and the second buffer is
+ * within the same page.  We expect to be able to map the first buffer. The
+ * second buffer cannot be mapped because it is not aligned.
+ *
+ * cuMemCreate + cuMemMap always return an aligned address. So, this test is
+ * for cuMemAlloc only.
+ *
+ */
+BEGIN_GDRCOPY_TEST(basic_small_buffers_mapping)
+{
+    expecting_exception_signal = false;
+    MB();
+
+    init_cuda(0);
+
+    const size_t fa_size = GPU_PAGE_SIZE;
+    CUdeviceptr d_fa;
+    gpu_mem_handle_t fa_mhandle;
+    ASSERTDRV(gpu_mem_alloc(&fa_mhandle, fa_size, true, true));
+    d_fa = fa_mhandle.ptr;
+    print_dbg("Allocated d_fa=%#llx, size=%zu\n", d_fa, fa_size);
+
+    const size_t buffer_size = sizeof(uint64_t);
+    CUdeviceptr d_A[2];
+    d_A[0] = d_fa;
+    d_A[1] = d_fa + buffer_size;
+
+    gdr_t g = gdr_open_safe();
+
+    // Pin both buffers.
+    print_dbg("Try pinning d_A[0] and d_A[1].\n");
+    gdr_mh_t A_mh[2];
+    A_mh[0] = null_mh;
+    A_mh[1] = null_mh;
+
+    ASSERT_EQ(gdr_pin_buffer(g, d_A[0], buffer_size, 0, 0, &A_mh[0]), 0);
+    ASSERT_EQ(gdr_pin_buffer(g, d_A[1], buffer_size, 0, 0, &A_mh[1]), 0);
+    ASSERT_NEQ(A_mh[0], null_mh);
+    ASSERT_NEQ(A_mh[1], null_mh);
+
+    void *A_bar_ptr[2];
+    A_bar_ptr[0] = NULL;
+    A_bar_ptr[1] = NULL;
+
+    // Expect gdr_map to pass
+    ASSERT_EQ(gdr_map(g, A_mh[0], &A_bar_ptr[0], buffer_size), 0);
+    print_dbg("Mapping d_A[0] passed as expected.\n");
+
+    // Expect gdr_map to fail due to unaligned mapping
+    ASSERT_NEQ(gdr_map(g, A_mh[1], &A_bar_ptr[1], buffer_size), 0);
+    print_dbg("Mapping d_A[1] failed as expected.\n");
+
+    ASSERT_EQ(gdr_unmap(g, A_mh[0], A_bar_ptr[0], buffer_size), 0);
+
+    ASSERT_EQ(gdr_unpin_buffer(g, A_mh[0]), 0);
+    ASSERT_EQ(gdr_unpin_buffer(g, A_mh[1]), 0);
+
+    ASSERT_EQ(gdr_close(g), 0);
+
+    ASSERTDRV(gpu_mem_free(&fa_mhandle));
+
+    finalize_cuda(0);
+}
+END_GDRCOPY_TEST
+
 template <gpu_memalloc_fn_t galloc_fn, gpu_memfree_fn_t gfree_fn, filter_fn_t filter_fn>
 void data_validation()
 {
@@ -1904,6 +1972,7 @@ int main(int argc, char *argv[])
     tcase_add_test(tc_basic, basic_cumemalloc);
     tcase_add_test(tc_basic, basic_with_tokens);
     tcase_add_test(tc_basic, basic_unaligned_mapping);
+    tcase_add_test(tc_basic, basic_small_buffers_mapping);
     tcase_add_test(tc_basic, basic_child_thread_pins_buffer_cumemalloc);

     tcase_add_test(tc_data_validation, data_validation_cumemalloc);

