+static int gdrdrv_check_same_process(gdr_info_t *info, struct task_struct *tsk)
+{
+    BUG_ON(0 == info);
+    BUG_ON(0 == tsk);
+    return (info->pid == task_pid(tsk))        // either exactly the same task
+        || (info->tgid == task_tgid_nr(tsk)) ; // or tasks belonging to the task group
+}
+
